text:
blockquote {
  display: block;
  margin: var(--pico-typography-spacing-vertical) 0;
  padding: var(--pico-spacing);
  border-right: none;
  border-left: 0.25rem solid var(--pico-blockquote-border-color);
  border-inline-start: 0.25rem solid var(--pico-blockquote-border-color);
  border-inline-end: none;
}
blockquote footer {
  margin-top: calc(var(--pico-typography-spacing-vertical) * 0.5);
  color: var(--pico-blockquote-footer-color);
}

&::after {
	content: "";
	block-size: 100%;
	inline-size: 100%;
	position: absolute;
	inset-inline-start: 0;
	inset-inline-end: 0;
	inset-block-start: 0;
	border-style: solid;
	border-color: transparent;
	border-width: 0;
	border-radius: var(--spectrum-card-corner-radius);
	margin-block-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
	margin-inline-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
}

&::after {
  content: '';
  position: absolute;
  border-radius: inherit;
  pointer-events: none;
  inset: 0;
  z-index: -1;
  border: var(--base-button-classic-after-inset) solid transparent;
  background-clip: content-box;
  background-color: inherit;
  background-image: linear-gradient(var(--black-a1), transparent, var(--white-a2));
  box-shadow: inset 0 2px 3px -1px var(--white-a4);
}

@custom-media --OSdark        (prefers-color-scheme: dark);
@custom-media --OSlight       (prefers-color-scheme: light);

@custom-media --highContrast  (prefers-contrast: more);
@custom-media --lowContrast   (prefers-contrast: less);

@custom-media --invertedColors  (inverted-colors: inverted);
@custom-media --forcedColors  (forced-colors: active);

@custom-media --portrait      (orientation: portrait);
@custom-media --landscape     (orientation: landscape);

@custom-media --portrait      (orientation: portrait);
@custom-media --landscape     (orientation: landscape);

@custom-media --HDcolor       (dynamic-range: high) or (color-gamut: p3);

@custom-media --touch         (hover: none) and (pointer: coarse);
@custom-media --stylus        (hover: none) and (pointer: fine);
@custom-media --pointer       (hover) and (pointer: coarse);
@custom-media --mouse         (hover) and (pointer: fine);

[class*=hint--]:before, [class*=hint--]:after {
  position: absolute;
  transform: translate3d(0, 0, 0);
  visibility: hidden;
  opacity: 0;
  z-index: 1000000;
  pointer-events: none;
  transition: 0.3s ease;
  transition-delay: 0ms;
}
[class*=hint--]:hover:before, [class*=hint--]:hover:after {
  visibility: visible;
  opacity: 1;
  transition-delay: 100ms;
}

input:not([type=checkbox], [type=radio], [type=range], [type=file]):is([type=date], [type=datetime-local], [type=month], [type=time], [type=week]) {
  --pico-icon-position: 0.75rem;
  --pico-icon-width: 1rem;
  padding-right: calc(var(--pico-icon-width) + var(--pico-icon-position));
  background-image: var(--pico-icon-date);
  background-position: center right var(--pico-icon-position);
  background-size: var(--pico-icon-width) auto;
  background-repeat: no-repeat;
}
input:not([type=checkbox], [type=radio], [type=range], [type=file])[type=time] {
  background-image: var(--pico-icon-time);
}

[type=range]::-webkit-slider-runnable-track {
  width: 100%;
  height: 0.375rem;
  border-radius: var(--pico-border-radius);
  background-color: var(--pico-range-border-color);
  -webkit-transition: background-color var(--pico-transition), box-shadow var(--pico-transition);
  transition: background-color var(--pico-transition), box-shadow var(--pico-transition);
}

[type=range]::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 1.25rem;
  height: 1.25rem;
  margin-top: -0.4375rem;
  border: 2px solid var(--pico-range-thumb-border-color);
  border-radius: 50%;
  background-color: var(--pico-range-thumb-color);
  cursor: pointer;
  -webkit-transition: background-color var(--pico-transition), transform var(--pico-transition);
  transition: background-color var(--pico-transition), transform var(--pico-transition);
}

@media (prefers-reduced-motion: reduce) {
  *:not([aria-busy=true]),
  :not([aria-busy=true])::before,
  :not([aria-busy=true])::after {
    background-attachment: initial !important;
    animation-duration: 1ms !important;
    animation-delay: -1ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-delay: 0s !important;
    transition-duration: 0s !important;
  }
}

@media only screen and (device-width <= 400px), only screen and (device-height <= 350px) {
	.spectrum-Modal--responsive {
		inline-size: 100%;
		block-size: 100%;
		max-inline-size: 100%;
		max-block-size: 100%;
		border-radius: 0;
	}

	.spectrum-Modal-wrapper .spectrum-Modal--responsive {
		margin-block-start: 0; /* Prevent the vertical offset bit */
	}
}

&:disabled,
    &[aria-disabled='true']:not([data-loading='true']) {
      color: var(--control-fgColor-disabled);
      background-color: var(--button-default-bgColor-disabled);
      border-color: var(--button-default-borderColor-disabled);
      box-shadow: none;

      & [data-kbd-chord] {
        background: var(--buttonKeybindingHint-default-bgColor-disabled);
        color: var(--buttonKeybindingHint-default-fgColor-disabled);
        border-color: var(--buttonKeybindingHint-default-borderColor-disabled);
      }
    }

&:disabled,
    &[aria-disabled='true']:not([data-loading='true']) {
      color: var(--button-primary-fgColor-disabled);
      background-color: var(--button-primary-bgColor-disabled);
      border-color: var(--button-primary-borderColor-disabled);
      box-shadow: none;

      & [data-kbd-chord] {
        background: var(--buttonKeybindingHint-primary-bgColor-disabled);
        color: var(--buttonKeybindingHint-primary-fgColor-disabled);
        border-color: var(--buttonKeybindingHint-primary-borderColor-disabled);
      }
    }

&:disabled,
    &[aria-disabled='true']:not([data-loading='true']) {
      color: var(--button-invisible-fgColor-disabled);
      background-color: var(--button-invisible-bgColor-disabled);
      border-color: var(--button-invisible-borderColor-disabled);
      box-shadow: none;

      & [data-kbd-chord] {
        background: var(--buttonKeybindingHint-invisible-bgColor-disabled);
        color: var(--buttonKeybindingHint-invisible-fgColor-disabled);
        border-color: var(--buttonKeybindingHint-invisible-borderColor-disabled);
      }
    }

@media (forced-colors: active) {
	.spectrum-InfieldButton {
		--highcontrast-infield-button-border-color: ButtonText;
		--highcontrast-infield-button-border-color-active: Highlight;

		&:disabled {
			--highcontrast-infield-button-border-color: inherit;
		}

		&:not(:disabled):hover,
		&:not(:disabled):active,
		&:not(:disabled):focus-visible {
			--highcontrast-infield-button-border-color: var(--highcontrast-infield-button-border-color-active);
		}
	}
}

@media (forced-colors: active) {
	.spectrum-Steplist {
		--highcontrast-steplist-complete-marker-background-color: CanvasText;
		--highcontrast-steplist-current-marker-color: Highlight;
		--highcontrast-steplist-current-marker-color-key-focus: Highlight;
	}

	@supports (color: SelectedItem) {
		.spectrum-Steplist {
			--highcontrast-steplist-current-marker-color: SelectedItem;
		}
	}
}

@media (forced-colors: active) {
	.spectrum-Tooltip {
		border: 1px solid transparent;
	}

	.spectrum-Tooltip-tip {
		--highcontrast-tooltip-background-color-default: CanvasText;
		--highcontrast-tooltip-background-color-informative: CanvasText;
		--highcontrast-tooltip-background-color-positive: CanvasText;
		--highcontrast-tooltip-background-color-negative: CanvasText;

		forced-color-adjust: none;
	}
}

@media ((max-width: calc(768px - 0.02px))) {
  .TablePaginationSteps[data-hidden-viewport-ranges*='narrow'] > *:not(:first-child):not(:last-child) {
    display: none;
  }

  .TablePaginationSteps[data-hidden-viewport-ranges*='narrow'] > *:first-child {
    margin-inline-end: 0;
  }

  .TablePaginationSteps[data-hidden-viewport-ranges*='narrow'] > *:last-child {
    margin-inline-start: 0;
  }
}

&.spectrum-BarLoader--overBackground,
  &.spectrum-BarLoader--staticWhite {
    .spectrum-BarLoader-fill {
      background: var(--spectrum-barloader-large-over-background-track-fill-color);
    }

    .spectrum-BarLoader-label,
    .spectrum-BarLoader-percentage {
      color: var(--spectrum-barloader-large-over-background-track-fill-color);
    }

    .spectrum-BarLoader-track {
      background-color: var(--spectrum-barloader-large-over-background-track-color);
    }
  }

&.spectrum-BarLoader--staticBlack {
  .spectrum-BarLoader-track {
    background-color: var(--spectrum-barloader-static-black-track-color);
  }

  .spectrum-BarLoader-label,
  .spectrum-BarLoader-percentage {
    color: var(--spectrum-barloader-static-black-fill-color);
  }

  .spectrum-BarLoader-fill {
    background: var(--spectrum-barloader-static-black-fill-color);
  }
}

&:hover {
	--mod-calendar-day-text-color: var(--spectrum-calendar-day-text-color-hover);

	&:not(.is-selection-end, .is-selection-start) {
		--mod-calendar-day-background-color: var(--spectrum-calendar-day-background-hover);
	}

	&.is-selected:not(.is-selection-end, .is-selection-start),
	&.is-range-selection {
		--mod-calendar-day-background-color: var(--spectrum-calendar-day-background-selected-hover);
	}
}

&.is-range-start,
		&.is-selection-start {
			padding-inline-end: var(--spectrum-calendar-day-padding);
			margin-inline-start: var(--spectrum-calendar-day-padding);

			border-start-start-radius: var(--spectrum-calendar-day-width);
			border-end-start-radius: var(--spectrum-calendar-day-width);

			&::before,
			&::after {
				inset-inline-start: 0;
			}
		}

&.is-drop-target {
	border-color: transparent;
	background-color: transparent;
	box-shadow: none;

	.spectrum-Card-preview {
		transition: none;
		background-color: var(--mod-card-preview-background-color, var(--mod-card-background-color, var(--spectrum-card-preview-background-color)));
	}

	.spectrum-Card-preview::before {
		border-color: var(--spectrum-card-focus-indicator-color);
		box-shadow: 0 0 0 1px var(--spectrum-card-focus-indicator-color);
	}
}

button[data-action="collapse-root"] {
	font-family: var(--spectrum-sans-font-family-stack);
	font-style: var(--spectrum-detail-sans-serif-font-style);
	font-weight: var(--spectrum-detail-sans-serif-font-weight);
	font-size: var(--spectrum-detail-size-m);
	margin-block-start: 0;
	margin-block-end: 0;

	color: var(--spectrum-detail-color);

	line-height: var(--spectrum-detail-line-height);
	letter-spacing: var(--spectrum-detail-letter-spacing);
	text-transform: uppercase;
}

&::after {
	content: "";
	block-size: 100%;
	inline-size: 100%;
	position: absolute;
	inset-inline-start: 0;
	inset-inline-end: 0;
	inset-block-start: 0;
	border-style: solid;
	border-color: transparent;
	border-width: 0;
	border-radius: calc(var(--spectrum-card-corner-radius) + var(--spectrum-card-focus-indicator-width));
	margin-block-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
	margin-inline-start: calc(-1 * var(--spectrum-card-focus-indicator-width));
}

%spectrum-overlay {
	pointer-events: none;
	visibility: hidden;
	opacity: 0;
	transition:
		transform var(--mod-overlay-animation-duration, var(--spectrum-animation-duration-100, 130ms)) ease-in-out,
		opacity var(--mod-overlay-animation-duration, var(--spectrum-animation-duration-100, 130ms)) ease-in-out,
		visibility 0ms linear var(--mod-overlay-animation-duration, var(--spectrum-animation-duration-100, 130ms));
}

@media (forced-colors: active) {
	.spectrum-DatePicker {
		--highcontrast-datepicker-dash-color: CanvasText;
		--highcontrast-datepicker-focus-ring-color: Highlight;
		--highcontrast-datepicker-pickerbutton-border-color: Highlight;

		&.is-disabled {
			--highcontrast-datepicker-dash-color: GrayText;
		}

		&.spectrum-DatePicker--quiet.is-invalid {
			--highcontrast-datepicker-pickerbutton-border-color: Highlight;
		}
	}
}

&:hover {
	color: var(--mod-accordion-item-header-color-hover, var(--spectrum-accordion-item-header-color-hover));
	background-color: var(--mod-accordion-background-color-hover, var(--spectrum-accordion-background-color-hover));

	+ .spectrum-Accordion-itemIconContainer {
		color: var(--mod-accordion-item-header-color-hover, var(--spectrum-accordion-item-header-color-hover));
	}
}

&:focus-visible {
	border-radius: var(--mod-accordion-corner-radius, var(--spectrum-accordion-corner-radius));

	outline: var(--mod-accordion-focus-indicator-thickness, var(--spectrum-accordion-focus-indicator-thickness)) solid var(--mod-accordion-focus-indicator-color, var(--spectrum-accordion-focus-indicator-color));
	background-color: var(--mod-accordion-background-color-key-focus, var(--spectrum-accordion-background-color-key-focus));
	color: var(--mod-accordion-item-header-color-key-focus, var(--spectrum-accordion-item-header-color-key-focus));
	outline-offset: calc(var(--mod-accordion-focus-indicator-gap, var(--spectrum-accordion-focus-indicator-gap)) * -1);
}

&::after {
	position: absolute;
	inset: 0;

	margin: calc((var(--spectrum-actionbutton-focus-indicator-gap) + var(--spectrum-actionbutton-border-width)) * -1);

	border-radius: var(--mod-actionbutton-focus-indicator-border-radius, calc(var(--spectrum-actionbutton-border-radius) + var(--spectrum-actionbutton-focus-indicator-gap)));

	transition: box-shadow var(--mod-actionbutton-animation-duration, var(--spectrum-animation-duration-100)) ease-in-out;

	pointer-events: none;
	content: "";
}
